Implement the try_all degradation policy that attempts connection through each proxy sequentially until one succeeds.

## Rationale

Health checks can have false negatives (proxy actually works but health check fails). For availability-critical use cases, it's better to try each proxy and see if any work, rather than giving up immediately.

## Implementation Details

```rust
pub async fn apply_try_all_policy(
    config: &AppConfig,
    target: &str,
) -> Result<(TcpStream, String)> {
    tracing::warn!(
        "All proxies unhealthy, trying each sequentially (try_all policy)"
    );

    // Sort by priority for deterministic order
    let mut proxies: Vec<_> = config.proxies.iter().collect();
    proxies.sort_by_key(|p| p.priority.unwrap_or(100));

    let mut last_error = None;

    for proxy in proxies {
        tracing::debug!(proxy = %proxy.id, "Attempting connection");

        match connect_through_proxy(proxy, target).await {
            Ok(stream) => {
                tracing::info!(
                    proxy = %proxy.id,
                    "Connection succeeded despite unhealthy status"
                );
                return Ok((stream, proxy.id.clone()));
            }
            Err(e) => {
                tracing::debug!(
                    proxy = %proxy.id,
                    error = %e,
                    "Connection attempt failed"
                );
                last_error = Some(e);
            }
        }
    }

    Err(last_error.unwrap_or_else(|| anyhow::anyhow!("No proxies configured")))
}

async fn connect_through_proxy(
    proxy: &ProxyConfig,
    target: &str,
) -> Result<TcpStream> {
    let proxy_addr = parse_proxy_address(&proxy.url)?;
    let timeout = Duration::from_secs(10); // Connection attempt timeout

    let stream = tokio::time::timeout(
        timeout,
        TcpStream::connect(&proxy_addr)
    ).await
        .context("Connection timeout")?
        .context("Failed to connect to proxy")?;

    // Could add CONNECT handshake here if needed
    Ok(stream)
}
```

